using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Provides atomic workspace-scoped inventory ledger persistence.</summary>
public interface IInventoryLedger
{
    /// <summary>Records a movement once for an idempotency key, returning null when its product or warehouse is unavailable.</summary>
    Task<InventoryMovement?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, InventoryMovementType type,
        decimal quantity, string idempotencyKey, DateTimeOffset occurredAtUtc, CancellationToken cancellationToken);

    /// <summary>Lists current balances, optionally restricted to a warehouse or product.</summary>
    Task<IReadOnlyList<InventoryBalance>> ListBalancesAsync(Guid workspaceId, Guid? warehouseId, Guid? productId,
        CancellationToken cancellationToken);
}

using MediatR;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Supplies receipt or issue input.</summary>
public sealed record RecordInventoryMovementRequest(Guid WarehouseId, Guid ProductId, decimal Quantity, string IdempotencyKey);

/// <summary>Records a receipt in the current workspace.</summary>
public sealed record RecordReceiptCommand(Guid WorkspaceId, Guid WarehouseId, Guid ProductId, decimal Quantity, string IdempotencyKey)
    : IRequest<InventoryMovementResponse?>;

/// <summary>Records an issue in the current workspace.</summary>
public sealed record RecordIssueCommand(Guid WorkspaceId, Guid WarehouseId, Guid ProductId, decimal Quantity, string IdempotencyKey)
    : IRequest<InventoryMovementResponse?>;

using MediatR;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Lists current workspace inventory balances.</summary>
public sealed record ListInventoryBalancesQuery(Guid WorkspaceId, Guid? WarehouseId, Guid? ProductId)
    : IRequest<IReadOnlyList<InventoryBalanceResponse>>;

using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Represents a recorded inventory movement exposed to clients.</summary>
public sealed record InventoryMovementResponse(Guid Id, Guid WarehouseId, Guid ProductId, InventoryMovementType Type,
    decimal Quantity, decimal BalanceAfterQuantity, DateTimeOffset OccurredAtUtc)
{
    /// <summary>Maps a ledger entry to a response.</summary>
    public static InventoryMovementResponse From(InventoryMovement movement) => new(movement.Id, movement.WarehouseId,
        movement.ProductId, movement.Type, movement.Quantity, movement.BalanceAfterQuantity, movement.OccurredAtUtc);
}

/// <summary>Represents current on-hand inventory exposed to clients.</summary>
public sealed record InventoryBalanceResponse(Guid WarehouseId, Guid ProductId, decimal Quantity)
{
    /// <summary>Maps a balance to a response.</summary>
    public static InventoryBalanceResponse From(InventoryBalance balance) => new(balance.WarehouseId, balance.ProductId, balance.Quantity);
}

using InventoryFlow.Domain.Entities;
using MediatR;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Handles receipt recording.</summary>
public sealed class RecordReceiptHandler(IInventoryLedger ledger, TimeProvider timeProvider)
    : IRequestHandler<RecordReceiptCommand, InventoryMovementResponse?>
{
    /// <inheritdoc />
    public async Task<InventoryMovementResponse?> Handle(RecordReceiptCommand request, CancellationToken cancellationToken)
    {
        var movement = await ledger.RecordAsync(request.WorkspaceId, request.WarehouseId, request.ProductId,
            InventoryMovementType.Receipt, request.Quantity, request.IdempotencyKey, timeProvider.GetUtcNow(), cancellationToken);
        return movement is null ? null : InventoryMovementResponse.From(movement);
    }
}

/// <summary>Handles issue recording.</summary>
public sealed class RecordIssueHandler(IInventoryLedger ledger, TimeProvider timeProvider)
    : IRequestHandler<RecordIssueCommand, InventoryMovementResponse?>
{
    /// <inheritdoc />
    public async Task<InventoryMovementResponse?> Handle(RecordIssueCommand request, CancellationToken cancellationToken)
    {
        var movement = await ledger.RecordAsync(request.WorkspaceId, request.WarehouseId, request.ProductId,
            InventoryMovementType.Issue, request.Quantity, request.IdempotencyKey, timeProvider.GetUtcNow(), cancellationToken);
        return movement is null ? null : InventoryMovementResponse.From(movement);
    }
}

/// <summary>Handles current balance listing.</summary>
public sealed class ListInventoryBalancesHandler(IInventoryLedger ledger)
    : IRequestHandler<ListInventoryBalancesQuery, IReadOnlyList<InventoryBalanceResponse>>
{
    /// <inheritdoc />
    public async Task<IReadOnlyList<InventoryBalanceResponse>> Handle(ListInventoryBalancesQuery request, CancellationToken cancellationToken) =>
        (await ledger.ListBalancesAsync(request.WorkspaceId, request.WarehouseId, request.ProductId, cancellationToken))
        .Select(InventoryBalanceResponse.From).ToArray();
}

using FluentValidation;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Validates inventory recording input.</summary>
public sealed class RecordReceiptCommandValidator : AbstractValidator<RecordReceiptCommand>
{
    /// <summary>Initializes validation rules.</summary>
    public RecordReceiptCommandValidator() => InventoryValidation.Configure(this);
}

/// <summary>Validates inventory issue input.</summary>
public sealed class RecordIssueCommandValidator : AbstractValidator<RecordIssueCommand>
{
    /// <summary>Initializes validation rules.</summary>
    public RecordIssueCommandValidator() => InventoryValidation.Configure(this);
}

internal static class InventoryValidation
{
    internal static void Configure<T>(AbstractValidator<T> validator) where T : class
    {
        validator.RuleFor(x => ((dynamic)x).WorkspaceId).NotEmpty();
        validator.RuleFor(x => ((dynamic)x).WarehouseId).NotEmpty();
        validator.RuleFor(x => ((dynamic)x).ProductId).NotEmpty();
        validator.RuleFor(x => ((dynamic)x).Quantity).GreaterThan(0m).Must(quantity => decimal.Round(quantity, 4) == quantity)
            .WithMessage("Quantity must have at most four decimal places.");
        validator.RuleFor(x => ((dynamic)x).IdempotencyKey).NotEmpty().MaximumLength(InventoryMovement.IdempotencyKeyMaxLength);
    }
}

